#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define i128 __int128
using namespace std;
const int N = 5e6+5;
struct line{LL k,b;};
LL n,m,Sum,Ans,t[N];
LL cnt[N],sum[N],MxTim,dp[N],st,ed,q[N];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
LL Calc(LL x,LL tim){return dp[x]-tim*cnt[x];}
bool Bad(LL a1,LL a2,LL a3){
    LL Lx=(dp[a2]-dp[a1])*(cnt[a3]-cnt[a2]);
    LL Rx=(dp[a3]-dp[a2])*(cnt[a2]-cnt[a1]);
    return (Lx>=Rx);
}
int main(){
    n=read(),m=read();
    Ans=0x3f3f3f3f3f3f3f3f;
    for(int i=1;i<=n;i++)
        t[i]=read()+1,MxTim=max(MxTim,t[i]),
        cnt[t[i]]++,Sum+=t[i];
    for(int i=1;i<=MxTim+m;i++)cnt[i]+=cnt[i-1];
    memset(dp,0x3f,sizeof(dp));
    dp[0]=0;st=1,ed=1,q[1]=0;
    for(int i=1;i<=MxTim+m;i++){
        if(i>m){
            while(st<ed&&Bad(q[ed-1],q[ed],i-m))ed--;
            q[++ed]=i-m;
        }while(st<ed&&Calc(q[st],i)>=Calc(q[st+1],i))st++;
        dp[i]=dp[q[st]]+i*(cnt[i]-cnt[q[st]]);
        if(i>=MxTim)Ans=min(Ans,dp[i]);
    }cout<<Ans-Sum<<"\n";
    return 0;
}
